-- Query: Query9
SELECT Customers.CustomerID, Customers.LastName, Customers.FirstName, Customers.S_LastName, Customers.S_FirstName, Customers.Gender, Customers.Address, Customers.City, Customers.State, Customers.ZipCode, Customers.Phone, Customers.Photographed, Customers.Deleted, Customers.DateDeleted, Customers.DeletedBy, Customers.Season, Customers.CurrentStatus, Customers.Update, Customers.Notes, Customers.EMail, Customers.Misc1, Customers.Misc2, Customers.Misc3, Customers.StudentID, Customers.SchoolID, Customers.CoCustomerID, Customers.WebPassword, Customers.Log, Customers.PrintedIDs, Customers.OverlayText, Customers.Retake, Customers.EMail2, Customers.Address2, Customers.City2, Customers.State2, Customers.ZipCode2, Customers.ProofBookFrontSession, Customers.ProofBookFrontPose, Customers.ProofBookBackSession, Customers.ProofBookBackPose, Customers.LastImportDate, Customers.MobilePhone1, Customers.MobilePhone2, Customers.LastUpdateUser, Customers.LastUpdateDate, Schools.School, Orders.OrderNumber, Orders.OrderDate, Orders.OrderTotal, Orders.DateShipped, Actions.Action, Actions.Date, ActionItems.Description, ActionItems.EmailSetup
FROM (Customers LEFT JOIN Schools ON Customers.SchoolID = Schools.SchoolID) LEFT JOIN ((Actions LEFT JOIN ActionItems ON Actions.Action = ActionItems.Action) RIGHT JOIN Orders ON Actions.OrderID = Orders.OrderID) ON Customers.CustomerID = Orders.CustomerID
WHERE (((Actions.Action)=12) AND ((Actions.Date)>=#1/1/2010# And (Actions.Date)<=#6/1/2010#));

